layui.use(["form","layer","upload"],function(){let form=layui.form;let layer=layui.layer;let upload=layui.upload;let options=[];let blogEntity;let blogEditor;if(blogId){$.ajax({url:"/blog_type",method:"GET",dataType:"json",success:function(a){if(a.request==="success"&&a.status===200){$.each(a.data,function(b,c){$("#type").append(new Option(c.name,c.name));options.push(c)});$.ajax({url:"/blog/"+blogId,method:"GET",dataType:"json",success:function(b){if(b.request==="success"&&b.status===200&&b.data){let blog=b.data[0];blogEntity=blog;$("#type option").each(function(c,d){if($(d).text()===blog.type){$(d).attr("selected","selected")}});form.val("form-blog",{id:blog.id,title:blog.title,author:blog.author,summary:blog.summary,contentMarkdown:blog.contentMarkdown});blogEditor=editormd("blog-editormd",EDITOR_CONFIG);form.render();$("#coverImage").attr("src",blog.coverImage)}else{layer.msg(b.message+", 错误码: "+b.status,{icon:2})}},error:function(b){if(b){layer.msg(b)}else{layer.msg("请求错误，请检查网络",{icon:2})}}})}},error:function(a){if(a){layer.msg(a)}else{layer.msg("请求错误，请检查网络",{icon:2})}}});form.verify({title:function(b,a){let titleRex=/^[\w\W\s\u4e00-\u9fcc]{4,30}$/;if(!titleRex.test(b)){return"标题只能为4-64个字符的字符串"}},author:function(b,a){let titleRex=/^[\w\W\s\u4e00-\u9fcc]{2,10}$/;if(!titleRex.test(b)){return"作者只能为2-10个字符"}},summary:function(b,a){let titleRex=/^[\w\W\s\u4e00-\u9fcc]{0,300}$/;if(!titleRex.test(b)){return"简介只能为0-300个字符"}}});form.on("submit(form-blog-submit)",function(a){let blog=a.field;let coverImage=$("#coverImage").attr("src")||IMG_DEFAULT;layer.confirm("确认提交？",{btn:["确认","取消"]},function(b){$.ajax({url:"/blog/"+blogId,data:{title:blog.title,author:blog.author,summary:blog.summary,type:blog.type,contentMarkdown:blogEditor.getMarkdown(),contentHtml:blogEditor.getHTML(),status:blogEntity.status,coverImage:coverImage,view:blogEntity.view,comment:blogEntity.comment},method:"PUT",dateType:"json",success:function(c){if(c.request==="success"&&c.status===200){layer.msg(c.message,{icon:1})}else{layer.msg(c.message+", 错误码: "+c.status,{icon:2})}},error:function(c){if(c){layer.msg(c)}else{layer.msg("请求错误，请检查网络",{icon:2})}}});layer.close(b)});return false});let uploadInst=upload.render({elem:"#upload-button",url:"/image/upload?token="+localStorage.getItem("token"),method:"POST",multiple:true,field:"file",before:function(a){a.preview(function(c,d,b){$("#coverImage").attr("src",b)})},done:function(a){if(a.request==="success"&&a.status===200){$("#coverImage").attr("src",a.data[0].url);layer.msg("上传成功！")}},error:function(){var a=$("#demoText");a.html('<span style="color: #FF5722;">上传失败</span> <a class="layui-btn layui-btn-xs demo-reload">重试</a>');a.find(".demo-reload").on("click",function(){uploadInst.upload()})}})}else{layer.msg("参数错误",{icon:2})}});